    INITIAL_CHAIN_ID = block.chainid;
    INITIAL_DOMAIN_SEPARATOR = computeDomainSeparator();
}

function percentMul(uint256 value, uint256 percentage) internal pure returns (uint256 result) {
  // to avoid overflow, value <= (type(uint256).max - HALF_PERCENTAGE_FACTOR) / percentage
  assembly {
    if iszero(
      or(
        iszero(percentage),
        iszero(gt(value, div(sub(not(0), HALF_PERCENTAGE_FACTOR), percentage)))
      )
    ) {
      revert(0, 0)
    }

    result := div(add(mul(value, percentage), HALF_PERCENTAGE_FACTOR), PERCENTAGE_FACTOR)
  }
}

function percentDiv(uint256 value, uint256 percentage) internal pure returns (uint256 result) {
  // to avoid overflow, value <= (type(uint256).max - halfPercentage) / PERCENTAGE_FACTOR
  assembly {
    if or(
      iszero(percentage),
      iszero(iszero(gt(value, div(sub(not(0), div(percentage, 2)), PERCENTAGE_FACTOR))))
    ) {
      revert(0, 0)
    }

    result := div(add(mul(value, PERCENTAGE_FACTOR), div(percentage, 2)), percentage)
  }
}

function calculateLinearInterest(
  uint256 rate,
  uint40 lastUpdateTimestamp
) internal view returns (uint256) {
  //solium-disable-next-line
  uint256 result = rate * (block.timestamp - uint256(lastUpdateTimestamp));
  unchecked {
    result = result / SECONDS_PER_YEAR;
  }

  return WadRayMath.RAY + result;
}

function setBorrowing(
  DataTypes.UserConfigurationMap storage self,
  uint256 reserveIndex,
  bool borrowing
) internal {
  unchecked {
    require(reserveIndex < ReserveConfiguration.MAX_RESERVES_COUNT, Errors.INVALID_RESERVE_INDEX);
    uint256 bit = 1 << (reserveIndex << 1);
    if (borrowing) {
      self.data |= bit;
    } else {
      self.data &= ~bit;
    }
  }
}

function isBorrowing(
  DataTypes.UserConfigurationMap memory self,
  uint256 reserveIndex
) internal pure returns (bool) {
  unchecked {
    require(reserveIndex < ReserveConfiguration.MAX_RESERVES_COUNT, Errors.INVALID_RESERVE_INDEX);
    return (self.data >> (reserveIndex << 1)) & 1 != 0;
  }
}

function cumulateToLiquidityIndex(
  DataTypes.ReserveData storage reserve,
  uint256 totalLiquidity,
  uint256 amount
) internal returns (uint256) {
  //next liquidity index is calculated this way: `((amount / totalLiquidity) + 1) * liquidityIndex`
  //division `amount / totalLiquidity` done in ray for precision
  uint256 result = (amount.wadToRay().rayDiv(totalLiquidity.wadToRay()) + WadRayMath.RAY).rayMul(
    reserve.liquidityIndex
  );
  reserve.liquidityIndex = result.toUint128();
  return result;
}

function isDeprecated(CToken cToken) public view returns (bool) {
    return
        markets[address(cToken)].collateralFactorMantissa == 0 &&
        borrowGuardianPaused[address(cToken)] == true &&
        cToken.reserveFactorMantissa() == 1e18
    ;
}

function floor(UD60x18 x) pure returns (UD60x18 result) {
    assembly ("memory-safe") {
        // Equivalent to `x % UNIT`.
        let remainder := mod(x, uUNIT)

        // Equivalent to `x - ((remainder > 0) ? remainder : 0)`.
        result := sub(x, mul(remainder, gt(remainder, 0)))
    }
}

function getSeaportMetadata()
        external
        pure
        override
        returns (
            string memory name,
            Schema[] memory schemas // map to Seaport Improvement Proposal IDs
        )
    {
        schemas = new Schema[](1);
        schemas[0].id = 3003;
        schemas[0].metadata = new bytes(0);

        return ("PausableZone", schemas);
    }

function bulkTransfer(
    TransferHelperItemsWithRecipient[] calldata items,
    bytes32 conduitKey
) external override returns (bytes4 magicValue) {
    // Ensure that a conduit key has been supplied.
    if (conduitKey == bytes32(0)) {
        revert InvalidConduit(conduitKey, address(0));
    }

    // Use conduit derived from supplied conduit key to perform transfers.
    _performTransfersWithConduit(items, conduitKey);

    // Return a magic value indicating that the transfers were performed.
    magicValue = this.bulkTransfer.selector;
}

function canCall(
    address user,
    address target,
    bytes4 functionSig
) public view virtual override returns (bool) {
    Authority customAuthority = getTargetCustomAuthority[target];

    if (address(customAuthority) != address(0)) return customAuthority.canCall(user, target, functionSig);

    return
        isCapabilityPublic[functionSig] || bytes32(0) != getUserRoles[user] & getRolesWithCapability[functionSig];
}

function _approve(address owner, address spender, uint256 amount) internal virtual {
    require(owner != address(0), "ERC20: approve from the zero address");
    require(spender != address(0), "ERC20: approve to the zero address");

    _allowances[owner][spender] = amount;
    emit Approval(owner, spender, amount);
}
